async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const pageState = await browser.checkPageState(
        `Product detail page for "${params.productName}" with an add-to-cart button visible`
    );

    if (!pageState.matched) {
        const searchInput = await browser.extractComponent<{ cssSelector: string; submitButtonCssSelector: string }>({
            typeName: 'SearchInput',
            schema: '{ cssSelector: string; submitButtonCssSelector: string; }'
        }, params.productName);
        if (!searchInput || !searchInput.cssSelector) {
            throw new Error('Could not find search input on this page');
        }
        await browser.clearAndType(searchInput.cssSelector, params.productName);
        if (searchInput.submitButtonCssSelector) {
            await browser.clickAndWait(searchInput.submitButtonCssSelector);
        } else {
            await browser.pressKey('Enter');
            await browser.awaitPageLoad();
        }

        const product = await browser.extractComponent<{ name: string; detailsLinkSelector: string }>({
            typeName: 'ProductTile',
            schema: '{ name: string; price: string; detailsLinkSelector: string; }'
        }, params.productName);
        if (!product || !product.detailsLinkSelector) {
            throw new Error('Could not find product: ' + params.productName);
        }
        await browser.clickAndWait(product.detailsLinkSelector);
    }

    const hero = await browser.extractComponent<{ name: string; addToCartButtonSelector?: string }>({
        typeName: 'ProductDetailsHero',
        schema: '{ name: string; price: string; addToCartButtonSelector?: string; }'
    }, params.productName);
    if (!hero || !hero.addToCartButtonSelector) {
        throw new Error('Could not find add-to-cart button on this page');
    }
    await browser.click(hero.addToCartButtonSelector);
    await browser.awaitPageInteraction();
    return { success: true, message: 'Added ' + (hero.name || params.productName) + ' to cart' };
}
